def _is_safe_expression(node):
    if isinstance(node, ast.Constant):
        return isinstance(node.value, (int, float))
    elif isinstance(node, ast.UnaryOp):
        return isinstance(node.op, (ast.UAdd, ast.USub)) and _is_safe_expression(node.operand)
    elif isinstance(node, ast.BinOp):
        return (type(node.op) in _OPERATORS and
                _is_safe_expression(node.left) and
                _is_safe_expression(node.right))
    else:
        return False

def _eval_ast(node):
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.UnaryOp):
        operand = _eval_ast(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
    elif isinstance(node, ast.BinOp):
        left = _eval_ast(node.left)
        right = _eval_ast(node.right)
        op_func = _OPERATORS[type(node.op)]
        return op_func(left, right)
    else:
        raise ValueError("Unsupported node")

