import re

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    """
    Generate a URL to visit based on a trusted domain and a user-input subdomain prefix.
    """
    if not subdomain_prefix:
        return f"https://{domain}"

    # Validate subdomain_prefix: only alphanumeric, hyphens, and dots allowed.
    # Each label (separated by dot) must be non-empty, not start or end with hyphen.
    labels = subdomain_prefix.split('.')
    for label in labels:
        if not label:
            return f"https://{domain}"
        if not re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9-]*[a-zA-Z0-9])?$', label):
            return f"https://{domain}"

    return f"https://{subdomain_prefix}.{domain}"

